Balance" DECIMAL(19,2) NOT NULL,     "initialInvestmentBalance" DECIMAL(19,2) NOT NULL,     "active" BOOLEAN NOT NULL DEFAULT true,     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "FinancialSettings_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "Category" (     "id" UUID NOT NULL,     "name" VARCHAR(120) NOT NULL,     "normalizedName" VARCHAR(120) NOT NULL,     "isActive" BOOLEAN NOT NULL DEFAULT true,     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "Category_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "MonthlyCompetency" (     "id" UUID NOT NULL,     "monthStart" DATE NOT NULL,     "controlStartDateSnapshot" DATE NOT NULL,     "status" "MonthlyCompetencyStatus" NOT NULL DEFAULT 'MATERIALIZED',     "openingOperationalBalance" DECIMAL(19,2) NOT NULL DEFAULT 0,     "openingInvestmentBalance" DECIMAL(19,2) NOT NULL DEFAULT 0,     "plannedSalaryInstallments" JSONB,     "plannedIncome" DECIMAL(19,2) NOT NULL DEFAULT 0,     "realizedIncome" DECIMAL(19,2) NOT NULL DEFAULT 0,     "plannedFixedExpenses" DECIMAL(19,2) NOT NULL DEFAULT 0,     "realizedExpenses" DECIMAL(19,2) NOT NULL DEFAULT 0,     "variableExpenses" DECIMAL(19,2) NOT NULL DEFAULT 0,     "installments" DECIMAL(19,2) NOT NULL DEFAULT 0,     "contributions" DECIMAL(19,2) NOT NULL DEFAULT 0,     "yields" DECIMAL(19,2) NOT NULL DEFAULT 0,     "operationalBalance" DECIMAL(19,2) NOT NULL DEFAULT 0,     "investmentBalance" DECIMAL(19,2) NOT NULL DEFAULT 0,     "plannedVsRealizedDelta" DECIMAL(19,2) NOT NULL DEFAULT 0,     "lastMaterializedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "MonthlyCompetency_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "RecurrenceRule" (     "id" UUID NOT NULL,     "description" VARCHAR(255) NOT NULL,     "categoryId" UUID NOT NULL,     "defaultAmount" DECIMAL(19,2) NOT NULL,     "dueDay" INTEGER NOT NULL,     "startDate" DATE NOT NULL,     "endDate" DATE,     "status" "RecurrenceRuleStatus" NOT NULL DEFAULT 'ACTIVE',     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "RecurrenceRule_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "FinancialEntry" (     "id" UUID NOT NULL,     "kind" "EntryKind" NOT NULL,     "direction" "EntryDirection" NOT NULL,     "status" "EntryStatus" NOT NULL DEFAULT 'PLANNED',     "origin" "EntryOrigin" NOT NULL DEFAULT 'MANUAL',     "description" VARCHAR(255) NOT NULL,     "normalizedDescription" VARCHAR(255) NOT NULL,     "categoryId" UUID,     "competencyMonth" DATE NOT NULL,     "plannedDate" DATE NOT NULL,     "effectiveDate" DATE,     "plannedAmount" DECIMAL(19,2) NOT NULL,     "effectiveAmount" DECIMAL(19,2),     "recurrenceRuleId" UUID,     "installmentItemId" UUID,     "generationKey" VARCHAR(150),     "duplicatedFromId" UUID,     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "FinancialEntry_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "InstallmentPlan" (     "id" UUID NOT NULL,     "description" VARCHAR(255) NOT NULL,     "categoryId" UUID NOT NULL,     "totalAmount" DECIMAL(19,2) NOT NULL,     "installmentCount" INTEGER NOT NULL,     "installmentAmount" DECIMAL(19,2) NOT NULL,     "purchaseDate" DATE NOT NULL,     "firstInstallmentMonth" DATE NOT NULL,     "paymentMethod" VARCHAR(80) NOT NULL,     "status" "InstallmentPlanStatus" NOT NULL DEFAULT 'ACTIVE',     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "InstallmentPlan_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "InstallmentItem" (     "id" UUID NOT NULL,     "installmentPlanId" UUID NOT NULL,     "installmentNumber" INTEGER NOT NULL,     "competencyMonth" DATE NOT NULL,     "amount" DECIMAL(19,2) NOT NULL,     "status" "InstallmentItemStatus" NOT NULL DEFAULT 'OPEN',     "financialEntryId" UUID,     "plannedDate" DATE NOT NULL,     "effectiveDate" DATE,     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "InstallmentItem_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "InvestmentMovement" (     "id" UUID NOT NULL,     "movementType" "InvestmentMovementType" NOT NULL,     "target" "AdjustmentTarget",     "direction" "AdjustmentDirection",     "description" VARCHAR(255) NOT NULL,     "competencyMonth" DATE NOT NULL,     "plannedDate" DATE NOT NULL,     "effectiveDate" DATE,     "plannedAmount" DECIMAL(19,2) NOT NULL,     "effectiveAmount" DECIMAL(19,2),     "status" "EntryStatus" NOT NULL DEFAULT 'PLANNED',     "auditEventId" UUID,     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "InvestmentMovement_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "AuditEvent" (     "id" UUID NOT NULL,     "entityName" VARCHAR(80) NOT NULL,     "entityId" UUID NOT NULL,     "operation" "AuditOperation" NOT NULL,     "changeOrigin" "ChangeOrigin" NOT NULL,     "previousValues" JSONB,     "nextValues" JSONB,     "occurredAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "performedBy" VARCHAR(80) NOT NULL DEFAULT 'local-user',      CONSTRAINT "AuditEvent_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "IdempotencyKey" (     "id" UUID NOT NULL,     "key" VARCHAR(150) NOT NULL,     "requestHash" VARCHAR(128) NOT NULL,     "responseStatus" INTEGER,     "responseBody" JSONB,     "expiresAt" TIMESTAMP(3) NOT NULL,     "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,      CONSTRAINT "IdempotencyKey_pkey" PRIMARY KEY ("id") );  -- CreateIndex CREATE INDEX "FinancialSettings_active_idx" ON "FinancialSettings"("active");  -- CreateIndex CREATE INDEX "Category_normalizedName_idx" ON "Category"("normalizedName");  -- CreateIndex CREATE UNIQUE INDEX "Category_normalizedName_isActive_key" ON "Category"("normalizedName", "isActive");  -- CreateIndex CREATE UNIQUE INDEX "MonthlyCompetency_monthStart_key" ON "MonthlyCompetency"("monthStart");  -- CreateIndex CREATE INDEX "MonthlyCompetency_controlStartDateSnapshot_idx" ON "MonthlyCompetency"("controlStartDateSnapshot");  -- CreateIndex CREATE INDEX "RecurrenceRule_categoryId_idx" ON "RecurrenceRule"("categoryId");  -- CreateIndex CREATE INDEX "RecurrenceRule_status_startDate_idx" ON "RecurrenceRule"("status", "startDate");  -- CreateIndex CREATE UNIQUE INDEX "FinancialEntry_installmentItemId_key" ON "FinancialEntry"("installmentItemId");  -- CreateIndex CREATE UNIQUE INDEX "FinancialEntry_generationKey_key" ON "FinancialEntry"("generationKey");  -- CreateIndex CREATE INDEX "FinancialEntry_competencyMonth_kind_status_idx" ON "FinancialEntry"("competencyMonth", "kind", "status");  -- CreateIndex CREATE INDEX "FinancialEntry_plannedDate_idx" ON "FinancialEntry"("plannedDate");  -- CreateIndex CREATE INDEX "FinancialEntry_effectiveDate_idx" ON "FinancialEntry"("effectiveDate");  -- CreateIndex CREATE INDEX "FinancialEntry_categoryId_competencyMonth_idx" ON "FinancialEntry"("categoryId", "competencyMonth");  -- CreateIndex CREATE INDEX "FinancialEntry_normalizedDescription_plannedAmount_plannedD_idx" ON "FinancialEntry"("normalizedDescription", "plannedAmount", "plannedDate");  -- CreateIndex CREATE INDEX "InstallmentPlan_categoryId_idx" ON "InstallmentPlan"("categoryId");  -- CreateIndex CREATE INDEX "InstallmentPlan_status_firstInstallmentMonth_idx" ON "InstallmentPlan"("status", "firstInstallmentMonth");  -- CreateIndex CREATE UNIQUE INDEX "InstallmentItem_financialEntryId_key" ON "InstallmentItem"("financialEntryId");  -- CreateIndex CREATE INDEX "InstallmentItem_competencyMonth_idx" ON "InstallmentItem"("competencyMonth");  -- CreateIndex CREATE INDE