PlanId") REFERENCES "InstallmentPlan"("id") ON DELETE RESTRICT ON UPDATE CASCADE;  -- AddForeignKey ALTER TABLE "InvestmentMovement" ADD CONSTRAINT "InvestmentMovement_auditEventId_fkey" FOREIGN KEY ("auditEventId") REFERENCES "AuditEvent"("id") ON DELETE SET NULL ON UPDATE CASCADE; 